/// <summary>
///     Extension class for form data source <c>SalesParmTable</c>
/// </summary>
[ExtensionOf(formDataSourceStr(SalesEditLines, SalesParmTable))]
internal final class ETGSalesEditLinesFormDS_Extension
{
}

Method.Source:
/// <summary>
/// This method makes TERMO fields visible if ETGEnableTermoNumberFeature is enabled in VendParameters
/// </summary>
public int active()
{
    int ret = next active();

    this.updateDesignETG();

    return ret;
}

/// <summary>
/// This methods makes custom fields visible from form datasource table SalesParmTable
/// </summary>
public void updateDesignETG()
{
    boolean        enableTermoNumberDesign;
    FormDataSource salesParmTable_ds       = this;
    SalesParmTable salesParmTableLoc       = salesParmTable_ds.cursor();
    InventParameters inventParameters = InventParameters::find();

    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes && salesParmTableLoc.Ordering == DocumentStatus::Invoice)
    {
        enableTermoNumberDesign = true;
    }

    salesParmTable_ds.object(fieldNum(SalesParmTable, ETGTERMONumber)).visible(enableTermoNumberDesign);
    salesParmTable_ds.object(fieldNum(SalesParmTable, ETGRemainingTermoValueReal)).visible(enableTermoNumberDesign);
    salesParmTable_ds.object(fieldNum(SalesParmTable, ETGRemainingClosedTERMOValueReal)).visible(enableTermoNumberDesign);
    salesParmTable_ds.object(fieldNum(SalesParmTable, ETGMotherTERMONumber)).visible(enableTermoNumberDesign);

    this.formRun().design().controlName(formControlStr(SalesEditLines, CoCoa)).visible(salesParmTableLoc.Ordering == DocumentStatus::Invoice 
        && inventParameters.ETGEnableQualityParameter);
    this.formRun().design().controlName(formControlStr(SalesEditLines, Cashew)).visible(salesParmTableLoc.Ordering == DocumentStatus::Invoice 
        && inventParameters.ETGEnableQualityParameter);
}
